SELECT id, account_id, game, item_count, fingerprint, created_at, last_seen_at
FROM inventory_snapshot
WHERE account_id = #{accountId}
  AND game = #{game}
ORDER BY created_at DESC
LIMIT 1

SELECT id, account_id, game, item_count, fingerprint, created_at, last_seen_at
FROM inventory_snapshot
WHERE account_id = #{accountId}
  AND id = #{snapshotId}
